export const SSEReactor = () => {
  const [events, setEvents] = useState<string[]>([]);
  const allEvents = [
    "data: { id: 101, type: 'init' }",
    "event: heartbeat",
    "data: { active: true }",
    "data: { cpu: '12%' }",
    "event: auth_success",
    "data: { status: 'stable' }",
    "data: { load: 'high' }",
    "event: sync_complete",
  ];

  useEffect(() => {
    let i = 0;
    const interval = setInterval(() => {
      setEvents((prev) => {
        const next = [...prev, allEvents[i % allEvents.length]];
        return next.slice(-3);
      });
      i++;
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="flex flex-col gap-1.5 w-full">
      <div className="flex items-center gap-2 mb-1">
        <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.5)]" />
        <span className="text-[9px] font-mono text-white/40 uppercase tracking-widest">
          axeom_sse.stream
        </span>
      </div>
      <div className="flex flex-col gap-1 overflow-hidden h-[40px]">
        {events.map((evt, idx) => (
          <div
            key={idx}
            className="text-[8px] font-mono text-white/20 whitespace-nowrap animate-in fade-in slide-in-from-bottom-1 duration-500"
          >
            <span className="text-white/40">{"> "}</span>
            {evt}
          </div>
        ))}
      </div>
    </div>
  );
};
